#include <iostream>
#include <stdexcept>
#include <string>

void level3(int d) {
    if (d == 3) throw std::runtime_error("from level 3");
}

void level2(int d) {
    if (d == 2) throw std::runtime_error("from level 2");
    level3(d);
}

void level1(int d) {
    if (d == 1) throw std::runtime_error("from level 1");
    level2(d);
}

int main() {
    int d;
    std::cin >> d;
    try {
        level1(d);
    } catch (const std::runtime_error& e) {
        std::cout << "caught " << e.what() << "\n";
    }
    return 0;
}

