solution_code:
#include <iostream>
#include <stdexcept>

int main() {
    int sel;
    std::cin >> sel;
    try {
        if (sel == 1)
            throw std::runtime_error("runtime problem");
        else
            throw std::invalid_argument("invalid argument");
    } catch (const std::runtime_error& e) {    // specific first
        std::cout << "runtime: " << e.what() << "\n";
    } catch (const std::exception& e) {        // general second
        std::cout << "generic: " << e.what() << "\n";
    }
    return 0;
}
